use std::collections::BinaryHeap;
use std::cmp::Ordering;

#[derive(Eq, PartialEq)]
struct State {
    min_cost: i64,
    total_cost: i64,
    node: usize,
}

impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        self.min_cost.cmp(&other.min_cost)
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

fn solve(edges: Vec<Vec<i64>>, online: Vec<bool>, k: i64) -> i64 {
    let n = online.len();
    let mut adj = vec![vec![]; n];
    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let cost = edge[2];
        adj[u].push((v, cost));
    }

    let mut max_heap = BinaryHeap::new();
    max_heap.push(State {
        min_cost: i64::MAX,
        total_cost: 0,
        node: 0,
    });

    let mut max_score = -1;

    while let Some(state) = max_heap.pop() {
        let current_min = state.min_cost;
        let total_cost = state.total_cost;
        let u = state.node;

        if u == n - 1 {
            if total_cost <= k {
                max_score = max_score.max(current_min);
            }
            continue;
        }

        for &(v, cost) in &adj[u] {
            if !online[v] && v != n - 1 {
                continue;
            }
            let new_total = total_cost + cost;
            if new_total > k {
                continue;
            }
            let new_min = if current_min == i64::MAX {
                cost
            } else {
                current_min.min(cost)
            };
            max_heap.push(State {
                min_cost: new_min,
                total_cost: new_total,
                node: v,
            });
        }
    }

    max_score
}
